checker_dsl:
EXISTS (`method M`) {
  AND {
    (`method M overrides android.webkit.WebViewClient.onReceivedSslError`),
    EXISTS (`method call MC`) {
      AND {
        (`method call MC invokes method android.webkit.SslErrorHandler.proceed`),
        (`method call MC's qualifier is a variable access VA`),
        (`variable access VA refers to the second parameter of method M`),
        (`basic block containing method call MC post-dominates the entry basic block of method M's body`)
      }
    }
  }
}
